AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]


def test_AC_A():
    """
    GIVEN: extract.py is fixed (sub-task B completed, including known-file entries for settings.json and settings.template.json) AND doc-sync regen has been run on the repo root
    WHEN:  the README.md AUTO block between <!-- AUTO:readme-stats --> and <!-- /AUTO:readme-stats --> is read
    THEN:  push.sh entry is non-empty AND requirements.txt shows something other than 'txt file' AND settings.json shows something other than 'json config' AND settings.template.json shows something other than 'json config' AND the AUTO block markers are still present
    """
    readme = REPO_ROOT / 'README.md'
    assert readme.exists(), "README.md not found"
    content = readme.read_text()

    # Verify AUTO block markers are present.
    assert '<!-- AUTO:readme-stats -->' in content, "AUTO block start marker missing"
    assert '<!-- /AUTO:readme-stats -->' in content, "AUTO block end marker missing"
    assert '*Auto-generated by doc-sync hook.*' in content, "Auto-generated footer missing"

    # Extract the AUTO block region.
    start = content.index('<!-- AUTO:readme-stats -->')
    end = content.index('<!-- /AUTO:readme-stats -->')
    auto_block = content[start:end]

    # push.sh must have a non-empty description (not just "- `push.sh` - ").
    push_match = re.search(r'- `push\.sh` - (.+)', auto_block)
    assert push_match, "push.sh entry not found in AUTO block"
    push_desc = push_match.group(1).strip()
    assert push_desc, f"push.sh description is empty"

    # requirements.txt must not show 'txt file'.
    assert '- `requirements.txt` - txt file' not in auto_block, \
        "requirements.txt still shows 'txt file'"

    # settings.json must not show 'json config'.
    assert '- `settings.json` - json config' not in auto_block, \
        "settings.json still shows 'json config'"

    # settings.template.json must not show 'json config'.
    assert '- `settings.template.json` - json config' not in auto_block, \
        "settings.template.json still shows 'json config'"
